(14, 'Welcome to the HumanOp Assessment (Powered by The ULT)', 'Welcome to the HumanOp Assessment (Powered by The ULT)', '', 'Welcome to the HumanOp Assessment (Powered by The ULT)', '<h3>\"Creating Perfect Relationships in Business, Home &amp; Life\"</h3>\r\n\r\nThis evolutionary Human Assessment Instrument enables professionals and\r\nindividuals to identify personal potential, human tolerance, perceptivity,\r\nmotivations and behavioral strengths &amp; weaknesses.\r\n\r\nTaking the test is a great opportunity for individuals seeking \r\nself-awareness to better understand themselves and others. \r\nThe technology is unique and is considered to be the most objective and&nbsp;first tool of \r\nchoice for those professionals seeking honest \r\nanswers for their clients and themselves.<br>', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(15, 'Personal Details', '', '', '', 'In order to start the test, please complete all fields in the form below.\r\n\r\nWe take your privacy very seriously. We will not sell, rent or share in any way your contact information with any other company, group or person.', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(16, 'CONGRATULATIONS!', 'CONGRATULATIONS!', 'CONGRATULATIONS!', 'CONGRATULATIONS!', '<h1><u>CONGRATULATIONS!</u></h1>\r\nYou have completed The Ultimate Life Tool Assessment!\r\n<br><br>We are confident that you will find the results of your report very \r\nvaluable and necessary in maximizing your personal performance in all \r\nareas of your life. If you would like more information about you and \r\noptimizing your performance or wish to inquire about services, training seminars \r\nand certification, please contact TYI at 760-230-8016.<br><span><br><b>Your\r\n results are currently being processed and you will be contacted by the practitioner that referred you.  Please reach out to them for any questions you may have.</b></span><br><br><br><br><br><br><br><br><br><br><br>', '2024-06-25 19:00:00', '2024-06-25 19:00:00');
