INSERT INTO `slides` (`id`, `slide_id`, `heading`, `body`, `sub`, `sub1`, `sub2`, `created_at`, `updated_at`) VALUES
(1, 1, 'The Cycle of Life', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(2, 3, 'It,s About Understanding What We See', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(3, 2, 'We Already Know How To See', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(4, 4, 'How We Go Against Nature and Burn Out', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(5, 5, 'The Knowledge of Y.O.U (Your Own Understanding)', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(6, 6, 'The Knowledge of Y.O.U', '<ul><li><font color=\"#ff0000\">TRAITS</font></li><li>\r\nMOTIVATIONS\r\n</li><li>BOUNDARIES\r\n</li><li>COMMUNICATION STYLE</li><li>\r\nENERGY &amp; PERCEPTION&nbsp;</li></ul>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(7, 7, 'TRAITS', '<p>The natural physical traits that make you unique:\r\nThe color of your hair and eyes, the shape of your face and other physical\r\ntraits all provide unique insight into your natural talents, capabilities and potential.</p>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(8, 9, 'The Knowledge of Y.O.U', '<ul><li>TRAITS\r\n</li><li><font color=\"#ff0000\">MOTIVATIONS\r\n</font></li><li>BOUNDARIES\r\n</li><li>COMMUNICATION STYLE\r\n</li><li>ENERGY &amp; PERCEPTION&nbsp;</li></ul>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(9, 10, 'MOTIVATIONS', '<p>There are 12 motivators or \"drivers\" in everyone,s vehicle of self but only\r\ntwo are authentically in the front seat navigating us through life.\r\nIdentifying what your two primary \"drivers\" are will help you to\r\nunderstand why you do things a certain way and what \"fuel\" you\r\nspecifically need in order to thrive.</p>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(10, 13, 'The Knowledge of Y.O.U', '<ul><li>TRAITS</li><li>\r\nMOTIVATIONS\r\n</li><li><font color=\"#ff0000\">BOUNDARIES</font></li><li>\r\nCOMMUNICATION STYLE\r\n</li><li>ENERGY &amp; PERCEPTION</li></ul>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(11, 14, 'BOUNDARIES', '<p>Boundaries address your personal preferences or level of\r\nrefinement. Identifying and understanding your boundaries\r\nof tolerance for others and in environments will help you to\r\nmaintain your energy and diffuse potential\r\nmisunderstandings with others.</p>', '<p>We use the analogy of ore to describe\r\nthis part of the knowledge.</p>', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(12, 15, 'The Cycle of Life', '', '<p>Fussy, Meticulous, Inflexible and Highly Refined</p>', '<p>Neat, Flexible, Practical, Solid, Durable and Adaptable</p>', '<p>Natural, Low Maintenance and Organic</p>', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(13, 16, 'GOLD Representation', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(14, 17, 'SILVER Representation', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(15, 18, 'COPPER Representation', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(16, 19, 'Places Have Alchemy', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(17, 20, 'Alchemic Dissonance (Incompatibility)', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(18, 22, 'Periodic Table of Alchemical Refinement', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(19, 23, 'The Knowledge of Y.O.U', '<ul><li>TRAITS</li><li>\r\nMOTIVATIONS</li><li>\r\nBOUNDARIES\r\n</li><li><font color=\"#ff0000\">COMMUNICATION STYLE</font></li><li>\r\nENERGY &amp; PERCEPTION&nbsp;</li></ul>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(20, 24, 'COMMUNICATION STYLE', '<p>There are 4 Energy Centers: Emotional, Moving, Intellectual\r\nand Instinctual. Understanding what your primary Energy Center is will\r\nreveal the specific way you connect with your environment, relate to\r\nothers and download information.</p>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(21, 25, 'ENERGY FIELD', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(22, 26, 'THE EMOTIONAL CENTER', '', '<ul><li>Connect with living thing</li><li>Feel everything</li><li>Nurturing</li><li>Passionate</li></ul>', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(23, 27, 'THE INSTINCTUAL CENTER', '', '<p>Happiest Sensing Life</p><ul><li>Look good</li><li>Sounds good</li><li>Smells good</li><li>Tastes good</li><li>Feels good</li></ul>', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(24, 28, 'THE INTELLECTUAL CENTER', '', '<p>Happiest entertaining new concepts</p><p>think rather then do</p><p>curl up with a good book</p><p>Engage in deep discussion</p>', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(25, 29, 'THE MOVING CENTER', '', '<p>Happiest when physically moving</p><p>Connect when moving</p><p>Download information best when moving</p>', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(26, 32, 'The Knowledge of Y.O.U', '<ul><li>TRAITS\r\n</li><li>MOTIVATIONS</li><li>\r\nBOUNDARIES</li><li>\r\nCOMMUNICATION STYLE</li><li><font color=\"#ff0000\">\r\nENERGY &amp; PERCEPTION</font>&nbsp;</li></ul>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(27, 33, 'ENERGY POOL', '<p>Your ENERGY POOL is simply how much physical energy you have to spend each day. The range is\r\n between 25 and 35.</p>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(28, 34, 'PERCEPTION', '<p>Your Ã¢â‚¬â€¢Perception of Life\" defines your electromagnetic potential You are either positively, negatively, or neutrally charged. Your perception reveals whether you see what is working first, what is not, or the ability to see both perspectives at the same time.&nbsp;</p>', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00'),
(29, 35, 'Polarity (Perception) & Energy Pool', '', '', '', '', '2024-06-25 19:00:00', '2024-06-25 19:00:00');
